import random
import time

class Lift:
    def __init__(self, id):
        self.id = id
        self.current_floor = 0
        self.passengers = 0

    def move_to_floor(self, floor):
        print(f"Lift {self.id} moving from floor {self.current_floor} to floor {floor}")
        self.current_floor = floor

    def pick_up_passengers(self, num_passengers):
        self.passengers += num_passengers
        print(f"Lift {self.id} picked up {num_passengers} passengers. Total now: {self.passengers}")

    def drop_off_passengers(self):
        print(f"Lift {self.id} dropping off {self.passengers} passengers at floor {self.current_floor}")
        self.passengers = 0

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(i) for i in range(num_lifts)]

    def simulate(self, crowd_size, time_of_day):
        if time_of_day in ['morning', 'evening']:
            for _ in range(crowd_size):
                floor = random.randint(0, self.num_floors - 1)
                lift = random.choice(self.lifts)
                lift.move_to_floor(floor)
                lift.pick_up_passengers(1)
                lift.drop_off_passengers()
        elif time_of_day == 'day':
            for _ in range(crowd_size // 2):
                floor = random.randint(0, self.num_floors - 1)
                lift = random.choice(self.lifts)
                lift.move_to_floor(floor)
                lift.pick_up_passengers(1)
                lift.drop_off_passengers()
        else:
            print("No significant lift activity at night.")

def run_simulation(num_floors, num_lifts, crowd_size):
    building = Building(num_floors, num_lifts)
    for time_of_day in ['morning', 'day', 'evening', 'night']:
        print(f"\n--- {time_of_day.capitalize()} Simulation ---")
        building.simulate(crowd_size, time_of_day)
        time.sleep(1)

