        print(f"Lift {self.id} picked up passenger {passenger} at floor {passenger['from_floor']}")

    def drop_off(self, passenger):
        self.passengers.remove(passenger)
        print(f"Lift {self.id} dropped off passenger {passenger} at floor {passenger['to_floor']}")

