        lift.drop_off(passenger)

    def find_nearest_lift(self, from_floor):
        return min(self.lifts, key=lambda lift: abs(lift.current_floor - from_floor))

    def simulate(self, crowd_size, time_of_day):
        for _ in range(crowd_size):
            from_floor = random.randint(0, self.num_floors - 1)
            to_floor = random.randint(0, self.num_floors - 1)
