class Lift:
    def __init__(self, id):
        self.id = id
        self.current_floor = 0
        self.direction = None
        self.passengers = []

    def move(self, target_floor):
        if self.current_floor < target_floor:
            self.direction = 'up'
        elif self.current_floor > target_floor:
            self.direction = 'down'
        else:
            self.direction = None

        while self.current_floor != target_floor:
            print(f"Lift {self.id} moving {self.direction} to floor {target_floor}")
            self.current_floor += 1 if self.direction == 'up' else -1
            time.sleep(0.5)

        self.direction = None

    def load_passengers(self, passengers):
        self.passengers.extend(passengers)

    def unload_passengers(self):
        self.passengers = []

