    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(i) for i in range(num_lifts)]

    def request_lift(self, floor, direction):
        available_lift = min(self.lifts, key=lambda lift: abs(lift.current_floor - floor))
        available_lift.move(floor)
        return available_lift

    def simulate(self, crowd_size, hours):
        for hour in hours:
            print(f"\nSimulating hour: {hour}")
