import random
import time

class Lift:
    def __init__(self, id):
        self.id = id
        self.current_floor = 0
        self.is_moving = False

    def move_to(self, floor):
        self.is_moving = True
        print(f"Lift {self.id} moving to floor {floor}")
        time.sleep(1)  # Simulate time taken to move
        self.current_floor = floor
        self.is_moving = False
        print(f"Lift {self.id} arrived at floor {floor}")

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(i) for i in range(num_lifts)]
        self.requests = []

    def request_lift(self, floor):
        self.requests.append(floor)
        print(f"Lift requested at floor {floor}")

    def serve_requests(self):
        for floor in self.requests:
            available_lift = self.find_available_lift()
            if available_lift:
                available_lift.move_to(floor)
        self.requests.clear()

    def find_available_lift(self):
        for lift in self.lifts:
            if not lift.is_moving:
                return lift
        return None

    def simulate(self, hours, crowd_size):
        for hour in range(hours):
            print(f"\nSimulating hour: {hour}")
            if hour < 8 or hour >= 17:  # Morning and evening rush hours
                for _ in range(crowd_size):
                    floor = random.randint(0, self.num_floors - 1)
                    self.request_lift(floor)
            elif hour < 17:  # Daytime
                if random.random() < 0.1:  # 10% chance of requests
                    for _ in range(crowd_size // 10):
                        floor = random.randint(0, self.num_floors - 1)
                        self.request_lift(floor)
            self.serve_requests()

if __name__ == "__main__":
