    def request_lift(self, requested_floor):
        available_lifts = [lift for lift in self.lifts if not lift.is_moving]
        if available_lifts:
            chosen_lift = random.choice(available_lifts)
            chosen_lift.move_to(requested_floor)
            return chosen_lift
        return None

