class Skyscraper:
    def __init__(self, floors, elevators):
        self.floors = floors
        self.elevators = elevators
        self.elevator_positions = [0] * elevators
        self.requests = []

    def request_elevator(self, floor):
        self.requests.append(floor)

    def simulate(self, time_steps):
        for t in range(time_steps):
            self.process_requests()
            self.move_elevators()
            self.log_state(t)

    def process_requests(self):
        for request in self.requests:
            closest_elevator = self.find_closest_elevator(request)
            self.elevator_positions[closest_elevator] = request
        self.requests.clear()

    def find_closest_elevator(self, request):
        return min(range(self.elevators), key=lambda i: abs(self.elevator_positions[i] - request))

    def move_elevators(self):
        for i in range(self.elevators):
            if self.elevator_positions[i] < self.floors - 1:
                self.elevator_positions[i] += 1
            elif self.elevator_positions[i] > 0:
                self.elevator_positions[i] -= 1

    def log_state(self, time_step):
        print(f"Time step {time_step}: Elevator positions: {self.elevator_positions}")

